import React, { useState, useEffect } from 'react';
import axios from 'axios';

const BookingList = () => {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchBookings = async () => {
      try {
        const token = localStorage.getItem('adminToken');
        const res = await axios.get('http://localhost:8080/bookings', { headers: { Authorization: `Bearer ${token}` } });
        setBookings(res.data || []);
      } catch (err) {
        console.error("Failed to fetch bookings:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchBookings();
  }, []);

  const handleDelete = async (id) => {
    if (!window.confirm("Are you sure you want to delete this booking?")) return;
    try {
      const token = localStorage.getItem('adminToken');
      await axios.delete(`http://localhost:8080/bookings/${id}`, { headers: { Authorization: `Bearer ${token}` } });
      setBookings(bookings.filter(b => b.id !== id));
    } catch (err) {
      alert("Failed to delete booking.");
    }
  };

  const handleStatusChange = async (id, newStatus, currentBooking) => {
    try {
      const token = localStorage.getItem('adminToken');
      const updatedBooking = { ...currentBooking, status: newStatus };
      await axios.put(`http://localhost:8080/bookings/${id}`, updatedBooking, { headers: { Authorization: `Bearer ${token}` } });

      // Update local state to reflect new status immediately without needing a refresh
      setBookings(bookings.map(b => b.id === id ? { ...b, status: newStatus } : b));
    } catch (err) {
      alert("Failed to update status.");
      console.error(err);
    }
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center py-12">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-green-600"></div>
      </div>
    );
  }

  if (bookings.length === 0) {
    return (
      <div className="text-center py-12">
        <p className="text-gray-500 font-medium text-lg">No bookings found.</p>
        <p className="text-gray-400 text-sm mt-1">Looks like the safari is quiet today.</p>
      </div>
    );
  }

  return (
    <div className="overflow-x-auto">
      <table className="min-w-full divide-y divide-gray-200">
        <thead className="bg-gray-50">
          <tr>
            <th scope="col" className="px-6 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">ID</th>
            <th scope="col" className="px-6 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Guest & Contact</th>
            <th scope="col" className="px-6 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Safari Details</th>
            <th scope="col" className="px-6 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Date & Zone</th>
            <th scope="col" className="px-6 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Status</th>
            <th scope="col" className="px-6 py-3 text-right text-xs font-bold text-gray-500 uppercase tracking-wider">Actions</th>
          </tr>
        </thead>
        <tbody className="bg-white divide-y divide-gray-200">
          {bookings.map((b) => (
            <tr key={b.id} className="hover:bg-gray-50 transition-colors">
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">#{b.id}</td>
              <td className="px-6 py-4 whitespace-nowrap">
                <div className="text-sm font-bold text-gray-900">{b.name}</div>
                <div className="text-xs text-gray-500 flex flex-col mt-0.5">
                  <span>{b.email}</span>
                  <span className="text-green-700 font-medium">{b.whatsapp}</span>
                  <span className="text-gray-400">{b.nationality}</span>
                </div>
              </td>
              <td className="px-6 py-4 whitespace-nowrap">
                <div className="text-sm text-gray-900">{b.vehicle}</div>
                <div className="text-xs text-gray-500 mt-0.5">{b.shift} Shift</div>
                <div className="text-xs font-medium text-amber-700 mt-0.5">{b.num_people} {b.num_people === 1 ? 'Person' : 'People'}</div>
              </td>
              <td className="px-6 py-4 whitespace-nowrap">
                <div className="flex flex-col items-start gap-1.5">
                  <span className="px-2.5 py-0.5 inline-flex text-xs leading-5 font-semibold rounded-full bg-blue-100 text-blue-800">
                    {new Date(b.date).toLocaleDateString()}
                  </span>
                  <span className="text-xs text-gray-600 font-medium">
                    {b.zone}
                  </span>
                </div>
              </td>
              <td className="px-6 py-4 whitespace-nowrap">
                <select
                  value={b.status || 'Fresh'}
                  onChange={(e) => handleStatusChange(b.id, e.target.value, b)}
                  className={`text-xs font-bold rounded-lg px-2 py-1.5 focus:outline-none focus:ring-2 focus:ring-green-500 transition-colors cursor-pointer border shadow-sm
                    ${b.status === 'Paid' ? 'bg-green-100 text-green-800 border-green-200' :
                      b.status === 'Done' ? 'bg-gray-200 text-gray-800 border-gray-300' :
                        b.status === 'Contacted' ? 'bg-amber-100 text-amber-800 border-amber-200' :
                          b.status === 'Cancelled' ? 'bg-red-100 text-red-800 border-red-200' :
                            'bg-blue-100 text-blue-800 border-blue-200'}
                  `}
                >
                  <option value="Fresh">Fresh</option>
                  <option value="Contacted">Contacted</option>
                  <option value="Paid">Paid</option>
                  <option value="Done">Done</option>
                  <option value="Cancelled">Cancelled</option>
                </select>
              </td>
              <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                <button
                  onClick={() => handleDelete(b.id)}
                  className="text-red-500 hover:text-red-700 bg-red-50 hover:bg-red-100 px-3 py-1 rounded-md transition-colors"
                >
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div >
  );
};

export default BookingList;
